#include "../../verification_stdlib.h"

/*@ Extern Coq (gcd_iterative_spec: Z -> Z -> Z -> Prop) */
/*@ Import Coq Require Import gcd_iterative */

int gcd_iterative(int a, int b)
/*@ Require
      0 <= a &&
      0 <= b &&
      (a != 0 || b != 0) &&
      emp
    Ensure
      gcd_iterative_spec(a@pre, b@pre, __return) && emp
*/
{
    int r;

    /*@ Assert exists a0 b0,
          a == a0 &&
          b == b0 &&
          emp
    */
    while (b != 0)
    /*@ Inv exists a0 b0 g,
          0 <= a &&
          0 <= b &&
          (a != 0 || b != 0) &&
          gcd_iterative_spec(a0, b0, g) &&
          gcd_iterative_spec(a, b, g) &&
          emp
    */
    {
        r = a % b;
        a = b;
        b = r;
    }

    /*@ Assert exists a0 b0,
          gcd_iterative_spec(a0, b0, a) &&
          emp
    */
    return a;
}

#include "../../verification_stdlib.h"

/*@ Extern Coq (gcd_iterative_spec: Z -> Z -> Z -> Prop) */
/*@ Import Coq Require Import gcd_iterative */

int gcd_iterative(int a, int b)
/*@ Require
      0 <= a &&
      0 <= b &&
      (a != 0 || b != 0) &&
      emp
    Ensure
      gcd_iterative_spec(a@pre, b@pre, __return) && emp
*/
{
    int r;

    while (b != 0) {
        r = a % b;
        a = b;
        b = r;
    }

    return a;
}

